    string largestPalindrome(int n, int k) {
        string res = "";
        for (int i = 9; i >= 1; i--) {
            string s = to_string(i);
            if (isPalindrome(s) && isDivisible(s, k)) {
                res = s;
                break;
            }
            for (int j = i; j >= 1; j--) {
                string temp = s + to_string(j);
                if (isPalindrome(temp) && isDivisible(temp, k)) {
                    res = temp;
                    break;
                }
            }
        }
        for (int i = 9; i >= 1; i--) {
            for (int j = i; j >= 1; j--) {
                string temp = to_string(j) + s + to_string(i);
                if (isPalindrome(temp) && isDivisible(temp, k)) {
                    res = temp;
                    break;
                }
            }
        }
        return res;
    }
    bool isPalindrome(string s) {
        int left = 0;
        int right = s.size() - 1;
        while (left < right) {
            if (s[left] != s[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
    bool isDivisible(string s, int k) {
        long long num = stoll(s);
        return num % k == 0;
    }
};
